// wrap in an IIFE to remove variables from global scope
(function () {
  "use strict";

  angular
    .module("folioApp", ["ui.router", "responsive-images"]) // eslint-disable-line no-undef
    .config(function (
      $stateProvider,
      $urlRouterProvider,
      $compileProvider,
      $locationProvider
    ) {
      $compileProvider.debugInfoEnabled(false);

      $locationProvider.html5Mode({
        enabled: true,
      });

      $stateProvider
        .state("developer", {
          url: "/developer",
          templateUrl: "templates/main/developer.html",
          controller: "DeveloperController",
        })
        .state("about", {
          url: "/about",
          templateUrl: "templates/main/about.html",
          controller: "DeveloperController",
        })
        .state("ideas", {
          url: "/ideas",
          templateUrl: "templates/main/ideas.html",
          controller: "DeveloperController",
        })
        .state("now", {
          url: "/now",
          templateUrl: "templates/main/now.html",
          controller: "DeveloperController",
        })
        .state("photographer", {
          url: "/photographer",
          templateUrl: "templates/main/photographer.html",
          controller: "PhotographerController",
        })
        .state("vera-photoshoot", {
          url: "/vera-photoshoot",
          templateUrl: "templates/photoshoots/vera-photoshoot.html",
          controller: "PhotographerController",
        })
        .state("japan-photoshoot", {
          url: "/japan-photoshoot",
          templateUrl: "templates/photoshoots/japan-photoshoot.html",
          controller: "PhotographerController",
        })
        .state("puerto-rico-photoshoot", {
          url: "/puerto-rico-photoshoot",
          templateUrl: "templates/photoshoots/puerto-rico-photoshoot.html",
          controller: "PhotographerController",
        })
        .state("washington-photoshoot", {
          url: "/washington-photoshoot",
          templateUrl: "templates/photoshoots/washington-photoshoot.html",
          controller: "PhotographerController",
        })
        .state("puerto-rico-2024-photoshoot", {
          url: "/puerto-rico-2024-photoshoot",
          templateUrl: "templates/photoshoots/puerto-rico-2024-photoshoot.html",
          controller: "PhotographerController",
        })
        .state("summer-2024-photoshoot", {
          url: "/summer-2024-photoshoot",
          templateUrl: "templates/photoshoots/summer-2024-photoshoot.html",
          controller: "PhotographerController",
        })
        .state("japan-taiwan-2024-photoshoot", {
          url: "/japan-taiwan-2024-photoshoot",
          templateUrl:
            "templates/photoshoots/japan-taiwan-2024-photoshoot.html",
          controller: "PhotographerController",
        })
        .state("ireland-2025-photoshoot", {
          url: "/ireland-2025-photoshoot",
          templateUrl: "templates/photoshoots/ireland-2025-photoshoot.html",
          controller: "PhotographerController",
        })
        .state("skillset", {
          url: "/skillset",
          templateUrl: "templates/projects/skillset.html",
          controller: "DeveloperController",
        })
        .state("etude", {
          url: "/etude",
          templateUrl: "templates/projects/etude.html",
          controller: "DeveloperController",
        })
        .state("reponotes", {
          url: "/reponotes",
          templateUrl: "templates/projects/reponotes.html",
          controller: "DeveloperController",
        })
        .state("tfstoolset", {
          url: "/tfstoolset",
          templateUrl: "templates/projects/tfstoolset.html",
          controller: "DeveloperController",
        });

      $urlRouterProvider.otherwise("/developer");
    })
    .run([
      "$transitions",
      "$rootScope",
      "$timeout",
      function ($transitions, $rootScope, $timeout) {
        function resetScrollPosition() {
          window.scrollTo(0, 0);
          document.body.scrollTop = 0;
          document.documentElement.scrollTop = 0;
        }

        function scheduleScrollReset() {
          resetScrollPosition();

          $timeout(resetScrollPosition, 0, false);
          $timeout(resetScrollPosition, 50, false);
          $timeout(resetScrollPosition, 150, false);
        }

        if ("scrollRestoration" in window.history) {
          window.history.scrollRestoration = "manual";
        }

        $transitions.onSuccess({}, function () {
          scheduleScrollReset();
        });

        $rootScope.$on("$viewContentLoaded", scheduleScrollReset);
      },
    ]);
})();

(function () {
  "use strict";

  angular // eslint-disable-line no-undef
    .module("folioApp")
    .controller("AboutController", [
      "$scope",
      "$location",
      "$anchorScroll",
      function ($scope, $location, $anchorScroll) {
        // set page class
        $scope.pageClass = "about";

        // utility function for linking between views
        $scope.go = function (path) {
          $location.path(path);
        };

        // utility function to add active css class to target element
        $scope.activate = function (event) {
          $(event.target).addClass("active"); // eslint-disable-line no-undef
        };

        // utility function to set viewport to the top of the page
        // on element click
        $scope.backToTop = function () {
          $anchorScroll();
        };

        // initialize blog container wrapper style
        var secondaryThemeHexCode = "#ffab40";

        if (document.querySelector("div.container.blog-container")) {
          document.body.parentNode.style.boxShadow =
            "0 0 0 5px " + secondaryThemeHexCode + " inset";
        } else {
          document.body.parentNode.style.boxShadow = "";
        }
      },
    ]);
})();

(function () {
  "use strict";

  angular // eslint-disable-line no-undef
    .module("folioApp")
    .controller("DeveloperController", [
      "$scope",
      "$location",
      "$anchorScroll",
      "$timeout",
      function ($scope, $location, $anchorScroll, $timeout) {
        function resetScrollPosition() {
          window.scrollTo(0, 0);
          document.body.scrollTop = 0;
          document.documentElement.scrollTop = 0;
        }

        // set page class
        $scope.pageClass = "developer";

        // utility function for linking between views
        $scope.go = function (path) {
          resetScrollPosition();
          $location.hash("");
          $location.path(path);
          $timeout(resetScrollPosition, 0, false);
          $timeout(resetScrollPosition, 75, false);
        };

        // page specific objects
        $scope.developerHeadshot = {
          url: "https://avatars3.githubusercontent.com/u/1449455?s=460&v=4",
          alt: "developer headshot"
        };

        $scope.softwareHeaderLink = {
          url: "https://www.github.com/Jac21"
        };

        $scope.fabButtonLinks = {
          email: "mailto:mail@jeremycantu.com?subject=Jeremy Cantú's Portfolio Inquiry&body=Let's talk!",
          file: "https://jac21.github.io/public/content/jCantuResume.pdf",
          github: "https://www.github.com/Jac21",
          linkedin: "https://www.linkedin.com/in/jeremycantu"
        };

        // utility function to add active css class to target element
        $scope.activate = function (event) {
          $(event.target).addClass("active"); // eslint-disable-line no-undef
        };

        // utility function to set viewport to the top of the page
        // on element click
        $scope.backToTop = function () {
          $anchorScroll();
        };

        resetScrollPosition();

        // initialize FAB
        var elem = document.querySelector(".fixed-action-btn");

        var instance = M.FloatingActionButton.init(elem, {
          direction: "left",
          hoverEnabled: false
        });

        // initialize materialbox
        var elem = document.querySelectorAll(".materialboxed");
        var instance = M.Materialbox.init(elem, {
          inDuration: 275,
          outDuration: 200
        });

        // initialize blog container wrapper style
        var secondaryThemeHexCode = "#ffab40";

        if (document.querySelector("div.container.blog-container")) {
          document.body.parentNode.style.boxShadow =
            "0 0 0 5px " + secondaryThemeHexCode + " inset";
        } else {
          document.body.parentNode.style.boxShadow = "";
        }
      }
    ]);
})();

